import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const redLessonsB1: Lesson[] = [
  createLesson('g1-red-b1-l1', 'L1: O que é Redação do ENEM?', 'redacao', 'A Redação do ENEM é uma prova separada, valendo de 0 a 1000 pontos, avaliada por duas bancas de forma independente (média das notas). Tipo textual obrigatório: dissertação argumentativa. Tema: sempre um problema social relevante para o Brasil. Textos motivadores: 4-5 textos que introduzem o tema (NÃO copiar — usar como referência). Estrutura básica: 4 parágrafos (introdução, desenvolvimento 1, desenvolvimento 2, conclusão). Extensão sugerida: 25-30 linhas. Por que a redação é importante: é 20% da nota de Linguagens.', ['O que a Redação do ENEM avalia? Quais são as diferenças com outras provas de redação que você fez?', 'Leia 3 temas do ENEM de anos anteriores: que característica todos têm em comum?']),
  createLesson('g1-red-b1-l2', 'L2: As 5 Competências da Banca', 'redacao', 'Competência 1: domínio da modalidade escrita formal (norma culta). Competência 2: compreensão do tema (tipo textual correto + aderência). Competência 3: seleção e organização de argumentos (progressão, coerência lógica). Competência 4: conhecimento dos mecanismos de coesão (conectivos, referências). Competência 5: proposta de intervenção detalhada e respeitosa aos direitos humanos. Cada competência vale 200 pontos. A nota de duas bancas é somada e dividida por 2. Nota 0: fuga do tema, texto não-dissertativo, em branco, ofensivo, cópia dos textos motivadores.', ['Explique com suas palavras cada uma das 5 competências.', 'Quais erros resultam em nota 0? Por que essas regras existem?']),
  createLesson('g1-red-b1-l3', 'L3: A Dissertação Argumentativa', 'redacao', 'Dissertação argumentativa: expõe e defende um ponto de vista sobre um tema. Diferente de: narração (conta história), descrição (descreve), dissertação expositiva (apenas informa). Características: tese clara, argumentação lógica, evidências, conclusão. Estrutura padrão ENEM: Parágrafo 1 — Introdução (contextualização + tese). Parágrafo 2 — 1º argumento + desenvolvimento. Parágrafo 3 — 2º argumento + desenvolvimento. Parágrafo 4 — Conclusão + proposta de intervenção. Foco: cada parágrafo tem uma função clara.', ['Identifique se estes textos são dissertações argumentativas ou outro tipo. Justifique.', 'Monte o esqueleto de uma dissertação sobre: "A importância da leitura para os jovens".']),
  createLesson('g1-red-b1-l4', 'L4: O Tema — Como Entender o que a Banca Quer', 'redacao', 'O tema do ENEM é sempre um PROBLEMA SOCIAL que tem pelo menos dois lados e afeta o Brasil. Ao receber o tema: 1) Identificar a QUESTÃO CENTRAL (não o assunto geral). 2) Identificar os TEXTOS MOTIVADORES e o que cada um traz. 3) Definir um RECORTE (aspecto específico do tema que você vai defender). 4) Formular a TESE (sua posição sobre o problema). Exemplo: tema "violência contra a mulher" → problema central: como enfrentá-la? Recorte possível: ausência de educação sobre equidade de gênero. Tese: o combate à violência passa pela educação.', ['Para estes 3 temas, identifique: o problema central, um recorte possível e uma tese.', 'O que é "fuga ao tema"? Explique com exemplos.']),
  createLesson('g1-red-b1-l5', 'L5: A Introdução — Contextualizando e Apresentando a Tese', 'redacao', 'A introdução tem 2 funções: contextualizar o tema e apresentar a tese. Contextualização: situar o leitor no assunto. Estratégias: dado estatístico ("Segundo o IBGE..."), citação de pensador ("Segundo Paulo Freire..."), alusão histórica (evento histórico relevante), pergunta retórica, comparação/contraste, apresentação do paradoxo. Tese: deve aparecer no FINAL da introdução — uma afirmação clara e argumentável sobre o problema. Não perguntar na tese — afirmar. Extensão da introdução: 5-7 linhas.', ['Analise estas 5 introduções: qual apresenta a tese de forma mais clara? Qual contextualiza melhor?', 'Escreva 3 introduções diferentes para o mesmo tema usando estratégias de contextualização diferentes.']),
  createLesson('g1-red-b1-l6', 'L6: Construindo o Argumento', 'redacao', 'Argumento: razão que sustenta a tese. Estrutura do parágrafo argumentativo: Tópico frasal → Desenvolvimento do argumento → Evidência (dado, exemplo, citação) → Fechamento/conexão com a tese. Tipos de argumento: Argumento de autoridade (citar especialista/lei/instituição), Argumento histórico (evento do passado como evidência), Argumento por exemplificação (caso concreto), Argumento causal (relação causa-consequência). Um argumento por parágrafo — desenvolvido, não superficial. "Desenvolver" significa: explicar, evidenciar, relacionar com o tema.', ['Desenvolva este argumento fraco em um parágrafo completo com tópico frasal, desenvolvimento e evidência.', 'Identifique o tipo de argumento em cada um destes parágrafos.']),
  createLesson('g1-red-b1-l7', 'L7: Tipos de Argumento — Prática', 'redacao', 'Prática de construção de diferentes tipos de argumento. Argumento de autoridade: "Segundo a Organização Mundial da Saúde (OMS)..." — citar corretamente (não inventar). Argumento histórico: "Durante o período da ditadura militar no Brasil (1964-1985)..." — ser preciso. Argumento por exemplificação: "No Tocantins, o programa X demonstra que..." — ser específico. Argumento causal: "A falta de X causa Y, que leva a Z..." — mostrar a cadeia lógica. Exercício: para um tema dado, construir um parágrafo de cada tipo de argumento.', ['Construa 4 parágrafos sobre o mesmo tema, cada um usando um tipo diferente de argumento.', 'Qual tipo de argumento você usa mais naturalmente? Qual é mais difícil para você?']),
  createLesson('g1-red-b1-l8', 'L8: A Conclusão e a Proposta de Intervenção', 'redacao', 'A conclusão tem duas partes: retomada da tese (de forma diferente, não cópia) e a proposta de intervenção. Proposta de intervenção (Competência 5): apresentar uma ação concreta para resolver o problema. Elementos obrigatórios para nota máxima: 1) Agente (quem vai agir?), 2) Ação (o que vai fazer?), 3) Meio/Modo (como vai fazer?), 4) Finalidade (para quê?), 5) Efeito/Detalhamento (o que vai mudar?). Extensão: 4-6 linhas. NÃO violar direitos humanos. NÃO ser vago ("o governo deve ajudar").', ['Identifique os elementos da proposta de intervenção neste parágrafo de conclusão.', 'Reescreva esta proposta vaga tornando-a específica com os 5 elementos.']),
  createLesson('g1-red-b1-l9', 'L9: Coesão — Conectando as Partes do Texto', 'redacao', 'Coesão textual: os "elos" que conectam as ideias. Conectivos essenciais para a redação do ENEM. Adição: além disso, ademais, também, outrossim. Oposição/concessão: entretanto, no entanto, todavia, porém, apesar disso, não obstante. Causa: porque, uma vez que, visto que, já que. Consequência: portanto, logo, assim, dessa forma, por isso. Conclusão: em suma, em síntese, conclui-se que. Exemplificação: por exemplo, a título de ilustração, como exemplo. Atenção: não use "mas" no início de parágrafo em texto formal.', ['Conecte estas frases usando os conectivos mais adequados para cada relação de sentido.', 'Reescreva esta redação sem conectivos e depois com conectivos: compare o efeito.']),
  createLesson('g1-red-b1-l10', 'L10: Coesão — Referência e Sinonímia', 'redacao', 'Além dos conectivos, a coesão também é feita por: referência pronominal (usar pronomes para retomar termos), elipse (omitir termos repetidos), sinonímia e hiponímia (usar palavras relacionadas para evitar repetição). Problema mais comum: repetir a palavra-tema 10 vezes por parágrafo. Solução: criar um "banco de sinônimos" para os termos do tema antes de escrever. Exemplo: tema "violência" → agressão, conflito, brutalidade, hostilidade. Prática: reescrever parágrafos substituindo repetições por referências e sinônimos.', ['Identifique as repetições neste parágrafo e reescreva usando referência e sinonímia.', 'Para o tema "desigualdade social", crie um banco de 10 sinônimos e expressões relacionadas.']),
  createLesson('g1-red-b1-l11', 'L11: Norma Culta na Redação', 'redacao', 'Competência 1: o que a banca avalia. Ortografia: acento, uso de maiúsculas, grafia correta. Pontuação: vírgula nos lugares certos (não separar sujeito do predicado!), ponto final, dois-pontos. Concordância: verbal e nominal — os erros mais comuns. Regência: usar a preposição correta. Colocação pronominal: próclise e ênclise. Nível de formalidade: sem gírias, sem contrações, sem primeira pessoa excessiva. Estratégia: reler o texto duas vezes antes de entregar — uma para conteúdo, uma para norma.', ['Encontre e corrija todos os erros de norma culta nesta redação de aluno.', 'Escreva um parágrafo sem nenhum erro de norma culta sobre o tema proposto.']),
  createLesson('g1-red-b1-l12', 'L12: Primeira Redação Completa', 'redacao', 'Primeira redação completa do ano: tema com textos motivadores (estilo ENEM). Processo: 1) Ler os textos motivadores (10 min). 2) Planejar (10 min): definir tese, escolher argumentos, planejar proposta. 3) Escrever (35 min): introdução, 2 parágrafos de desenvolvimento, conclusão. 4) Revisar (5 min): norma culta, coesão. Total: 60 minutos. Esta é uma prática — não uma avaliação definitiva. O objetivo é experimentar o processo completo. Compartilhar e discutir em grupo.', ['Escreva sua primeira redação completa em 60 minutos sobre o tema proposto.', 'Identifique os pontos fortes e fracos da sua redação usando as 5 competências.']),
  createLesson('g1-red-b1-l13', 'L13: Leitura e Análise de Redações', 'redacao', 'Aprender com redações reais: analisar exemplos de diferentes níveis. Redação nota 1000: o que tem de especial? Redação nota 600: o que falta? Redação nota 200: o que está muito errado? Análise competência por competência. Desenvolver o "olho crítico": ler a redação do colega com mais distância do que a própria. O papel da comparação: ver o que funciona e o que não funciona ajuda a internalizar os critérios. Prática: avaliar 3 redações usando a grade do ENEM.', ['Avalie estas 3 redações usando a grade de competências (nota 0-200 por competência).', 'Qual redação você mais aprendeu avaliando? Por quê?']),
  createLesson('g1-red-b1-l14', 'L14: Repertório Cultural — Construindo seu Banco', 'redacao', 'Repertório cultural: referências que enriquecem a argumentação. Categorias essenciais: 1) Filósofos e pensadores (Aristóteles, Kant, Foucault, Paulo Freire, Simone de Beauvoir). 2) Leis e documentos (Constituição Federal 1988, ECA, Convenções ONU). 3) Dados e estatísticas (IBGE, PNAD, Relatório ONU). 4) Eventos históricos. 5) Obras literárias. 6) Personalidades (cientistas, ativistas, políticos). Como usar o repertório: contextualizado, pertinente, não forçado. Construir um caderno de repertório.', ['Monte 5 fichas de repertório: nome/autor, o que defende, aplicação possível em redação.', 'Para o tema "educação", liste 3 repertórios pertinentes (dado, lei, pensador) que você usaria.']),
  createLesson('g1-red-b1-l15', 'L15: Temas Sociais — Educação e Desigualdade', 'redacao', 'Temas recorrentes do ENEM ligados a educação e desigualdade. Subtemas: acesso à educação, qualidade do ensino, educação inclusiva, desigualdade educacional, analfabetismo funcional, educação e tecnologia, evasão escolar, valorização do professor. Repertório específico: dados do INEP, PNAD, UNESCO. Paulo Freire: "Educação como prática de liberdade". Constituição Federal Art. 6º (educação como direito social). LDB (Lei 9.394/96). Prática de redação com tema de educação.', ['Planeje uma redação sobre: "Desafios para garantir o direito à educação de qualidade no Brasil".', 'Que dados e referências sobre educação você já tem? Pesquise 3 novas para seu banco.']),
  createLesson('g1-red-b1-l16', 'L16: Temas Sociais — Saúde e Meio Ambiente', 'redacao', 'Temas recorrentes: saúde pública, saneamento básico, meio ambiente, desenvolvimento sustentável, biomas brasileiros (Cerrado, Amazônia, Pantanal). No Tocantins: Cerrado, Araguaia, agricultura e meio ambiente. Repertório: OMS, IBGE, relatórios ambientais, Constituição (Art. 225 — direito ao meio ambiente). Conceito de desenvolvimento sustentável (Brundtland). Agenda 2030 da ONU (SDGs). Prática: planejar uma redação sobre preservação do Cerrado com argumentos e proposta específica para o Tocantins.', ['Planeje uma redação sobre preservação do Cerrado usando dados e exemplos do Tocantins.', 'A proposta de intervenção de uma redação ambiental deve mencionar quem? Quais ações?']),
  createLesson('g1-red-b1-l17', 'L17: Feedback e Reescrita', 'redacao', 'O feedback é um presente — não uma punição. Receber feedback: ouvir com abertura, perguntar se não entendeu, agradecer. Dar feedback: ser específico ("o argumento do parágrafo 2 não tem evidência" em vez de "parágrafo fraco"), ser construtivo (indicar o que melhorar), ser honesto. Reescrita: não apenas corrigir erros, mas melhorar a qualidade. Estratégia: reescrever um parágrafo completo, não apenas frases isoladas. Prática: reescrever a introdução ou a conclusão com base no feedback.', ['Reescreva sua introdução da última redação usando o feedback recebido.', 'Dê feedback específico para a redação de um colega: identifique 2 pontos fortes e 2 de melhoria.']),
  createLesson('g1-red-b1-l18', 'L18: Revisão do Bimestre 1', 'redacao', 'Revisão do 1º Bimestre de Redação: o ENEM e suas competências, dissertação argumentativa, entender o tema, introdução (contextualização + tese), tipos de argumento, conclusão e proposta de intervenção, coesão (conectivos, referência, sinonímia), norma culta, primeira redação completa, análise de redações, repertório cultural, temas (educação, saúde, meio ambiente), feedback e reescrita. Simulado de planejamento de redação. Autoavaliação: em que você mais melhorou?', ['Planeja uma redação completa (sem escrever o texto — apenas o esqueleto + argumentos + proposta) para o tema proposto.', 'Avalie: qual das 5 competências você ainda tem mais dificuldade?']),
];

export const redLessonsB2: Lesson[] = [
  createLesson('g1-red-b2-l1', 'L1: Aprofundando a Tese', 'redacao', 'A tese é o coração da redação. Uma boa tese: específica (não genérica), argumentável (tem dois lados), relevante (responde ao problema do tema), posicionada (toma partido). Tese fraca: "A violência é um problema sério." Tese forte: "A ausência de políticas públicas de prevenção à violência urbana, aliada à ineficácia do sistema prisional, perpetua um ciclo que penaliza principalmente as populações periféricas." Como formular: identificar o recorte → construir a tese como resposta ao problema. Exercício: reformular teses fracas.', ['Identifique as teses fracas e reformule-as tornando-as específicas e posicionadas.', 'Escreva 3 teses diferentes para o mesmo tema, cada uma com um recorte diferente.']),
  createLesson('g1-red-b2-l2', 'L2: Argumento de Autoridade — Usando Bem', 'redacao', 'O argumento de autoridade é poderoso, mas exige cuidado. Como usar corretamente: "Segundo [autoridade], [ideia]". Autoridades válidas: filósofos, sociólogos, economistas, organizações internacionais, leis, pesquisas. Erros comuns: inventar citação, citar sem pertinência, usar citação sem desenvolver. Citação como ponto de partida: introduzir a ideia e então desenvolvê-la, conectando com a tese. Repertório de autoridades por tema: Foucault (poder), Bourdieu (capital cultural), Freire (educação), Simone de Beauvoir (feminismo), Karl Marx (capitalismo), Yuval Noah Harari (modernidade).', ['Para 5 temas, indique um pensador pertinente e explique por que ele é adequado.', 'Use esta citação de Paulo Freire em um parágrafo argumentativo de forma pertinente e desenvolvida.']),
  createLesson('g1-red-b2-l3', 'L3: Argumento por Dados — Números que Convencem', 'redacao', 'Dados estatísticos dão credibilidade ao argumento. Como usar: "De acordo com o IBGE (ano)...", "Segundo dados da OMS...", "Conforme levantamento do PNAD...". O que NÃO fazer: inventar dados, usar dados imprecisos, usar dado sem desenvolver. Dados por tema: educação (INEP), saúde (DATASUS/OMS), violência (IPEA/Fórum Brasileiro de Segurança Pública), meio ambiente (INPE/MapBiomas), desigualdade (Coeficiente de Gini/IBGE). Como organizar um banco de dados reais para usar na redação.', ['Para cada tema, aponte um dado estatístico real e como ele seria usado em um argumento.', 'Construa um parágrafo argumentativo usando um dado do IBGE sobre desigualdade de renda.']),
  createLesson('g1-red-b2-l4', 'L4: A Proposta de Intervenção Perfeita', 'redacao', 'A proposta de intervenção é a parte mais esquecida e mais fácil de aprimorar. Revisão dos 5 elementos. Exemplos de propostas completas vs. incompletas. Nível de especificidade: "O governo" (vago) → "O Ministério da Saúde" (específico) → "O Ministério da Saúde, em parceria com prefeituras municipais" (muito específico). Ações específicas vs. vagas: "fazer campanhas" (vago) → "lançar campanhas de conscientização em redes sociais e unidades de saúde básica" (específico). Finalidade clara. Efeito esperado.', ['Reescreva estas 3 propostas de intervenção vagas tornando-as completas e específicas.', 'Crie uma proposta de intervenção com todos os 5 elementos para o tema: saúde mental dos jovens.']),
  createLesson('g1-red-b2-l5', 'L5: A Progressão Temática', 'redacao', 'Progressão temática: como o texto avança. A redação não pode ser "estática" (ficar falando da mesma coisa de ângulos diferentes). Cada parágrafo deve AVANÇAR a discussão. Tipos de progressão: tema contínuo (o tema do parágrafo 1 é retomado e aprofundado no 2), progressão linear (o rema do parágrafo 1 se torna o tema do parágrafo 2), progressão com tema derivado (cada parágrafo desenvolve um aspecto diferente do tema geral). Avaliar a progressão: ler apenas as primeiras frases de cada parágrafo — elas devem criar uma sequência lógica.', ['Analise a progressão temática desta redação: o texto avança ou fica estático?', 'Reordene os parágrafos desta redação para criar uma progressão mais lógica.']),
  createLesson('g1-red-b2-l6', 'L6: Contra-argumento e Concessão', 'redacao', 'Antecipar o contra-argumento demonstra sofisticação intelectual (Competência 3). Concessão: admitir que há outro lado válido. Refutação: mostrar por que sua tese prevalece. Estrutura: "Embora X seja verdade (concessão), Y prevalece porque Z (refutação e argumento principal)." Isso não é "mudar de opinião" — é fortalecer a tese mostrando que você considerou o outro lado. Exemplos: "Apesar de a tecnologia ter democratizado a informação, é necessário reconhecer que o acesso desigual à internet aprofunda a exclusão digital."', ['Reescreva estes argumentos unilaterais adicionando concessão e refutação.', 'Para o tema proposto, qual seria o principal contra-argumento? Como você responderia a ele?']),
  createLesson('g1-red-b2-l7', 'L7: Temas Sociais — Violência e Segurança', 'redacao', 'Temas recorrentes: violência urbana, segurança pública, violência doméstica, feminicídio, racismo, bullying. Repertório: Lei Maria da Penha (11.340/2006), Estatuto da Criança e do Adolescente, dados do Fórum Brasileiro de Segurança Pública, dados do IPEA sobre violência. Conceito de violência estrutural (Galtung). Interseccionalidade: gênero, raça, classe e vulnerabilidade à violência. Prática: planejar e escrever um parágrafo argumentativo sobre violência usando dados reais.', ['Escreva um parágrafo argumentativo sobre violência doméstica usando dados reais e Lei Maria da Penha.', 'Qual é a diferença entre abordar "violência" de forma genérica vs. com um recorte específico?']),
  createLesson('g1-red-b2-l8', 'L8: Temas Sociais — Tecnologia e Comunicação', 'redacao', 'Temas recorrentes: desinformação/fake news, redes sociais, privacidade de dados, exclusão digital, inteligência artificial, cyberbullying. Repertório: LGPD (Lei Geral de Proteção de Dados, 13.709/2018), dados do IBGE sobre acesso à internet, pesquisa TIC Domicílios (Cetic.br). Conceito de bolha informacional e câmara de eco. Marco Civil da Internet (12.965/2014). Prática: escrever uma dissertação completa sobre o impacto das redes sociais na saúde mental dos jovens.', ['Escreva uma redação completa sobre: "Impacto das redes sociais na saúde mental dos jovens brasileiros".', 'Avalie sua redação: você usou pelo menos uma lei/dado específico? A proposta é detalhada?']),
  createLesson('g1-red-b2-l9', 'L9: Parágrafos de Alta Qualidade', 'redacao', 'O que diferencia um parágrafo médio de um excelente? Tópico frasal preciso (não vago), desenvolvimento completo (não apenas 2 linhas), evidência pertinente (dado, citação, exemplo), fechamento que conecta com a tese. O parágrafo de desenvolvimento ideal tem 6-9 linhas. Estrutura DEEP: D (Declaração — tópico frasal), E (Evidência — dado/citação/exemplo), E (Explicação — desenvolver o argumento), P (Posição — conectar com a tese). Exercício: transformar parágrafos rasos em parágrafos profundos.', ['Analise estes parágrafos usando o modelo DEEP: o que falta em cada um?', 'Escreva um parágrafo de desenvolvimento com mínimo 7 linhas usando o modelo DEEP.']),
  createLesson('g1-red-b2-l10', 'L10: A Escrita como Processo', 'redacao', 'Escrever bem não é talento — é processo e prática. O processo de escrita: pré-escrita (brainstorming, pesquisa, planejamento), escrita (rascunho), pós-escrita (revisão, edição, reescrita). Na redação do ENEM: comprimido em 60 minutos, mas o processo existe (10 min planejar, 40 escrever, 10 revisar). Desenvolvimento do hábito: escrever regularmente, mesmo fora das aulas. Diário de escrita, blog, textos espontâneos. A escrita como ferramenta de pensamento: ao escrever, você organiza suas ideias.', ['Escreva um diário de reflexão sobre sua evolução na escrita argumentativa até aqui.', 'Qual parte do processo de escrita é mais difícil para você: planejamento, escrita ou revisão?']),
  createLesson('g1-red-b2-l11', 'L11: Segunda Redação Completa', 'redacao', 'Segunda redação completa do ano. Tema proposto com textos motivadores. 60 minutos. Aplicar tudo do B1 e B2: tese específica, argumento com evidência, contra-argumento/concessão, proposta com 5 elementos, coesão aprimorada. Antes de escrever: 10 minutos de planejamento rigoroso (esqueleto no rascunho). Comparar com a primeira redação: houve evolução? Em que aspecto mais? Feedback detalhado por competência.', ['Escreva a segunda redação completa (60 minutos).', 'Compare a nota desta redação com a primeira: houve evolução? Em qual competência foi mais significativa?']),
  createLesson('g1-red-b2-l12', 'L12: Planejamento da Redação — Método Eficaz', 'redacao', 'O planejamento antes de escrever é fundamental para uma redação coerente. Método em 10 minutos: 1) Ler o tema e os textos motivadores (2 min). 2) Identificar o problema social (1 min). 3) Definir o recorte e a tese (1 min). 4) Escolher 2 argumentos principais (2 min). 5) Escolher evidências para cada argumento (2 min). 6) Planejar a proposta de intervenção com os 5 elementos (2 min). O rascunho de planejamento: pode usar esquema, tópicos, mapa mental. Não perder tempo escrevendo o texto completo no rascunho — escrever diretamente.', ['Pratique o método de planejamento em 10 minutos para o tema proposto.', 'Compare sua redação quando planeja vs. quando não planeja: qual é a diferença na qualidade?']),
  createLesson('g1-red-b2-l13', 'L13: Temas Sociais — Identidade e Diversidade', 'redacao', 'Temas recorrentes: cotas raciais, quilombolas, povos indígenas, diversidade cultural, LGBTQIA+, pessoas com deficiência (PcD), inclusão social. Repertório: Lei 12.711/2012 (cotas), Estatuto da Igualdade Racial, Convenção 169 da OIT (povos indígenas), Lei Brasileira de Inclusão (13.146/2015). Conceitos: interseccionalidade, representatividade, equidade vs. igualdade. Abordar temas de diversidade com respeito e precisão (Competência 5: direitos humanos). Prática: redação sobre inclusão de pessoas com deficiência.', ['Escreva um parágrafo argumentativo sobre cotas raciais usando dados e argumentos equilibrados.', 'Qual é a diferença entre "igualdade" e "equidade"? Como isso afeta a argumentação sobre cotas?']),
  createLesson('g1-red-b2-l14', 'L14: Revisão por Pares — Método Estruturado', 'redacao', 'A revisão por pares é uma ferramenta poderosa de aprendizado. Método estruturado: 1) Ler a redação completa (sem marcar). 2) Avaliar cada competência (0-200) com justificativa. 3) Identificar o ponto mais forte. 4) Identificar o ponto de maior melhoria com sugestão específica. 5) Dar feedback oral complementar. Receber o feedback: registrar, não defender imediatamente, perguntar se não entendeu. O objetivo não é "dar nota" — é ajudar o colega a crescer. Ética do feedback: honesto, específico, respeitoso.', ['Faça a revisão por pares estruturada da redação de um colega usando o método.', 'Que feedback você recebeu? Como vai aplicar na próxima redação?']),
  createLesson('g1-red-b2-l15', 'L15: Temas Sociais — Trabalho e Economia', 'redacao', 'Temas recorrentes: desemprego, uberização/trabalho gig, desigualdade salarial, trabalho infantil, reforma trabalhista, empreendedorismo. Repertório: CLT (Consolidação das Leis do Trabalho), IBGE (taxa de desemprego), PNAD, Agenda 2030 ONU (trabalho decente). Conceitos: precarização do trabalho, trabalho informal, automação e emprego. Desigualdade salarial de gênero e raça. Prática: redação sobre a precarização do trabalho no Brasil contemporâneo.', ['Escreva um parágrafo argumentativo sobre a uberização do trabalho usando dados e conceitos precisos.', 'Como a automação pode ser tanto um problema quanto uma oportunidade? Use isso em um argumento.']),
  createLesson('g1-red-b2-l16', 'L16: Temas Transversais — Saúde Mental', 'redacao', 'Saúde mental dos jovens: tema crescente e muito provável no ENEM. Subtemas: depressão, ansiedade, cyberbullying, pressão escolar, uso de substâncias, suicídio (abordar com cuidado — valorização da vida). Repertório: dados do CFP (Conselho Federal de Psicologia), OMS, IBGE sobre saúde mental de adolescentes. Setembro Amarelo (prevenção ao suicídio). CVV (Centro de Valorização da Vida). Como abordar com responsabilidade: foco em prevenção, tratamento, acesso ao serviço de saúde mental — sem romantizar o sofrimento.', ['Planeje uma redação sobre saúde mental dos jovens que respeite a dignidade e os direitos humanos.', 'Como abordar o suicídio em uma redação sem violar a Competência 5 (direitos humanos)?']),
  createLesson('g1-red-b2-l17', 'L17: Redação — Revisão Completa de Erros', 'redacao', 'Aula de revisão centrada nos erros mais comuns identificados nas redações do 1º semestre. Erros de C1: concordância, pontuação, repetição de palavras. Erros de C2: tangenciamento do tema, introdução sem tese clara. Erros de C3: argumento sem desenvolvimento, sem evidência. Erros de C4: falta de conectivos, pronome sem antecedente. Erros de C5: proposta vaga, faltando elementos, violação de direitos humanos. Para cada erro: exemplos reais (anonimizados) e correção. Construção de uma lista pessoal de erros a evitar.', ['Monte sua lista pessoal: os 3 erros que você mais comete e como vai evitá-los.', 'Corrija esta redação problemática identificando e resolvendo erros em todas as 5 competências.']),
  createLesson('g1-red-b2-l18', 'L18: Revisão do Bimestre 2', 'redacao', 'Revisão do 2º Bimestre: aprofundamento da tese, tipos de argumento (autoridade, dados, exemplificação, histórico), proposta de intervenção perfeita, progressão temática, contra-argumento e concessão, temas (violência, tecnologia, identidade/diversidade, trabalho, saúde mental), parágrafos de alta qualidade, processo de escrita, planejamento em 10 minutos, revisão por pares. Terceira redação completa como avaliação do bimestre.', ['Escreva a redação de avaliação do 2º Bimestre (60 minutos) sobre o tema proposto.', 'Avalie sua evolução: compare as 3 redações escritas até agora. Qual competência cresceu mais?']),
];

export const redLessonsB3: Lesson[] = [
  createLesson('g1-red-b3-l1', 'L1: Redação no 2º Semestre — Intensificação', 'redacao', 'Entrando no 2º semestre: tempo de intensificar a prática. Metas do 2º semestre: escrever pelo menos uma redação por semana (na escola + em casa), rever cada redação escrita, identificar o erro recorrente e focar nele. A mentalidade do escritor em treinamento: cada redação é uma oportunidade de crescer, não apenas de "ter uma nota". Análise de desempenho até aqui: notas por competência ao longo do semestre — trajetória de crescimento. O que mudar na segunda metade do ano.', ['Analise suas redações do 1º semestre: em qual competência você mais cresceu? Qual ainda precisa de atenção?', 'Qual é seu plano de treino de redação para o 2º semestre?']),
  createLesson('g1-red-b3-l2', 'L2: Análise de Temas do ENEM Real', 'redacao', 'Análise dos temas do ENEM ao longo dos anos (2009-2024). Padrões: sempre um problema social com aspectos contraditórios, sempre ligado ao Brasil contemporâneo, sempre com textos motivadores que dão perspectivas diferentes. Temas dos últimos anos: trabalho infantil (2018), democratização do cinema (2018 ppt), manipulação do comportamento do usuário (2017), violência contra a mulher (2015), publicidade infantil (2014). Que temas podem aparecer nos próximos anos? Preparação temática ampla vs. específica.', ['Analise o tema de uma ENEM dos últimos 3 anos: como você o abordaria?', 'Faça uma lista de 10 temas prováveis para o próximo ENEM com base nos padrões históricos.']),
  createLesson('g1-red-b3-l3', 'L3: Introdução Criativa — Estratégias Avançadas', 'redacao', 'Introduções que se destacam. Estratégia 1: Intertextualidade — começar com referência literária, filosófica ou histórica. "Ao afirmar que \'a miséria é inimiga da virtude\', o filósofo Rousseau antecipava...". Estratégia 2: Paradoxo — "Vivemos na era da informação, mas nunca a desinformação foi tão perigosa." Estratégia 3: Dado impactante — "De acordo com o IBGE, 1 em cada 3 mulheres brasileiras já foi vítima de violência doméstica." Estratégia 4: Narrativa de caso — brevemente referenciar um caso simbólico. Prática: escrever 3 introduções diferentes para o mesmo tema.', ['Escreva 3 introduções para o mesmo tema usando estratégias diferentes.', 'Qual estratégia de contextualização funciona melhor para você? Por quê?']),
  createLesson('g1-red-b3-l4', 'L4: Conclusão com Impacto', 'redacao', 'Conclusão que fecha com força. Elementos: retomada da tese (não cópia — reformulação com outras palavras) + proposta de intervenção detalhada + frase de fechamento com impacto. Estratégias para a frase final: referência ao início (criando circularidade), citação pertinente, projeção para o futuro, apelo aos valores. O que evitar: "Diante do exposto, conclui-se que..." (clichê) → preferir frases mais criativas. A conclusão não é sumário — é síntese. A proposta deve ser a parte mais específica e original da redação.', ['Escreva 3 conclusões diferentes para o mesmo tema, cada uma com uma estratégia de fechamento diferente.', 'Reescreva esta conclusão clichê tornando-a mais específica e com maior impacto.']),
  createLesson('g1-red-b3-l5', 'L5: Coesão Avançada — Sofisticando os Conectivos', 'redacao', 'Elevando o nível da coesão. Conectivos mais sofisticados para substituir os comuns. Em vez de "mas" → contudo, todavia, não obstante, outrossim (concessão). Em vez de "porque" → haja vista que, porquanto, visto que. Em vez de "além disso" → ademais, destarte, outrossim, para além disso. Em vez de "por isso" → destarte, depreende-se que, nesse sentido. Atenção: usar com propriedade — o conectivo errado é pior que um simples "porque". Prática: substituir conectivos simples por sofisticados em redações reais.', ['Substitua os conectivos simples por variações mais sofisticadas nesta redação.', 'Quais conectivos você ainda não usa com segurança? Crie 3 frases com cada um.']),
  createLesson('g1-red-b3-l6', 'L6: Quarta Redação Completa', 'redacao', 'Quarta redação completa: tema com textos motivadores, 60 minutos. Aplicar todas as técnicas aprendidas: introdução criativa, argumentos com evidências sólidas (dados + lei ou citação), contra-argumento/concessão, coesão avançada com conectivos sofisticados, proposta com os 5 elementos bem detalhados. Foco especial: a proposta de intervenção (identificar agente, ação, meio, finalidade, efeito antes de escrever). Autoavaliação antes de receber o feedback do professor.', ['Escreva a quarta redação completa (60 minutos).', 'Faça a autoavaliação da sua redação antes de receber o feedback. Depois compare as avaliações.']),
  createLesson('g1-red-b3-l7', 'L7: Temas Difíceis — Como Abordar', 'redacao', 'Alguns temas são mais difíceis de abordar porque são polêmicos ou exigem equilíbrio. Estratégia: focar no aspecto SOCIAL do problema, não na disputa ideológica. Aborto → foco no acesso à saúde e na autonomia da mulher (sem defender ou contra). Pena de morte → foco no sistema penal e na ressocialização. Cotas → foco nas desigualdades históricas e nos direitos humanos. Eutanásia → foco na dignidade e na autonomia do paciente. Regra de ouro: a solução proposta deve ser possível dentro do Estado Democrático de Direito.', ['Como você abordaria o tema "aborto" em uma redação do ENEM sem violar os direitos humanos?', 'Pratique: escreva apenas a introdução de uma redação sobre cotas raciais com equilíbrio.']),
  createLesson('g1-red-b3-l8', 'L8: Temas Contemporâneos — IA e Futuro do Trabalho', 'redacao', 'Temas de fronteira: inteligência artificial, automação, futuro do trabalho, metaverso, biotecnologia, geopolítica do clima. Estes temas podem aparecer no ENEM dos próximos anos. Repertório: Klaus Schwab ("A Quarta Revolução Industrial"), OIT (relatórios sobre futuro do trabalho), IBGE (dados de emprego), Marco Legal da IA no Brasil. Como abordar o novo: usar o conhecimento interdisciplinar (Biologia, Física, Ciências Humanas). A redação como demonstração de conhecimento integrado.', ['Planeja uma redação sobre: "Desafios da regulação da inteligência artificial no Brasil".', 'Como você conectaria o tema de IA com direitos humanos em uma proposta de intervenção?']),
  createLesson('g1-red-b3-l9', 'L9: Temas Ambientais — Cerrado e Tocantins', 'redacao', 'O Cerrado como tema de redação: o bioma mais ameaçado do Brasil. Dados: segundo o MapBiomas, o Cerrado já perdeu mais de 50% de sua cobertura original. Biodiversidade: berço das águas (nascentes dos principais rios do Brasil). Conflito: agronegócio x preservação. Tocantins: estado majoritariamente no Cerrado, com Araguaia e Tocantins como rios estruturantes. Proposta específica para o Tocantins: políticas de pagamento por serviços ambientais, educação ambiental nas escolas, fiscalização do desmatamento. Redação com dados locais.', ['Escreva uma redação sobre a preservação do Cerrado usando dados e exemplos do Tocantins.', 'A proposta de intervenção de uma redação ambiental deve envolver que agentes do Tocantins?']),
  createLesson('g1-red-b3-l10', 'L10: Revisão da Escrita — Erros que Custam Pontos', 'redacao', 'Erros que impactam mais a nota. C1: concordância sujeito-verbo em frases complexas ("Um dos problemas que mais afeta..."), crase ("à medida que" vs. "à proporção que"), vírgula antes do "que" subordinativo. C3: argumento sem desenvolvimento (apenas 2 linhas por parágrafo). C4: usar o mesmo conectivo repetido (e... e... e... ou além disso... além disso...). C5: proposta vaga ou com ação impossível. Estratégia: ter um checklist pessoal dos 5 erros que você mais comete e verificar cada um antes de entregar.', ['Monte seu checklist pessoal de revisão com os 5 erros que você mais comete.', 'Use o checklist para revisar esta redação: identifique e corrija cada problema.']),
  createLesson('g1-red-b3-l11', 'L11: Quinta Redação — Simulado', 'redacao', 'Quinta redação completa em condições de simulado rigoroso. Tema social com textos motivadores. Exatamente 60 minutos. Sem consulta. Foco: aplicar o checklist pessoal de revisão nos últimos 10 minutos. Avaliação rigorosa — como a banca do ENEM avaliaria. Comparação com todas as redações anteriores: trajetória de crescimento ao longo do semestre. Nota projetada: em que patamar você está? Para chegar a 800+, o que ainda falta?', ['Escreva a quinta redação em condições de simulado (60 minutos rigorosos).', 'Compare todas as suas 5 redações: monte um gráfico de evolução das notas por competência.']),
  createLesson('g1-red-b3-l12', 'L12: Leitura como Suporte para a Escrita', 'redacao', 'Ler mais melhora a escrita — como e por quê. A leitura fornece: modelos de estrutura argumentativa, vocabulário rico, repertório cultural, modelos de coesão. O que ler para melhorar a redação: editoriais de jornais (O Globo, Folha de S.Paulo, Correio Braziliense), revistas de atualidades (Piauí, Agência Pública), artigos de divulgação científica. Como ler ativamente: identificar tese, argumentos, conectivos, proposta. Imitar conscientemente: escrever um parágrafo no estilo de um editorial que você admirou.', ['Leia um editorial de jornal e identifique: tese, argumento principal, conectivos usados, conclusão.', 'Escreva um parágrafo argumentativo "no estilo" de um editorial que você admirou.']),
  createLesson('g1-red-b3-l13', 'L13: Revisão por Competência — Foco em C3', 'redacao', 'Aula dedicada à Competência 3 (Argumentação). O que a banca avalia: coerência do ponto de vista, seleção e organização dos argumentos, progressão temática, profundidade de análise. Como elevar a C3: desenvolver cada argumento (não apenas enunciar), usar evidências variadas, mostrar cadeia causal, conectar cada argumento com a tese de forma explícita. Análise de redações com C3 alta (180-200) vs. baixa (40-80). O que diferencia: a profundidade, não a quantidade.', ['Analise a C3 desta redação: os argumentos são desenvolvidos? Há progressão? Reformule o mais fraco.', 'Reescreva seu parágrafo mais fraco do último simulado elevando a Competência 3.']),
  createLesson('g1-red-b3-l14', 'L14: Preparação para o Final do Ano', 'redacao', 'Balanço do ano de Redação na 1ª série. O que você aprendeu: as 5 competências, a estrutura dissertativa, tipos de argumento, coesão, norma culta, proposta de intervenção, temas sociais recorrentes, repertório cultural. O que ainda precisa desenvolver: identificar suas lacunas persistentes. Plano para as férias: ler editoriais, praticar planejamentos de redação (sem escrever o texto inteiro), anotar repertório cultural. Preparação para a 2ª série: o que esperar e como continuar crescendo.', ['Faça um portfólio das suas 5 redações do ano com autoavaliação de cada uma.', 'Escreva uma reflexão: o que você aprendeu sobre sua própria escrita neste ano?']),
  createLesson('g1-red-b3-l15', 'L15: Tema Livre — Expressão Autoral', 'redacao', 'Exercício de escrita dissertativa com tema de escolha do aluno. Objetivo: demonstrar autonomia argumentativa — escolher um problema social real que você conhece e argumentar sobre ele. O texto mais autêntico geralmente é o mais forte. Sua vivência no Tocantins, na escola, na família — tudo pode gerar argumento genuíno. A voz autoral: não é sobre "escrever bonito", é sobre ter algo real a dizer e dizê-lo com clareza, coerência e coesão.', ['Escreva uma dissertação argumentativa sobre um tema social de sua escolha com autenticidade.', 'Compartilhe sua redação com a turma: o que tornou esta dissertação mais pessoal?']),
  createLesson('g1-red-b3-l16', 'L16: Temas Ligados à Cultura e Arte', 'redacao', 'Temas recorrentes: democratização da cultura, acesso a museus/cinema/teatro, culturas populares (forró, funk, axé, sertanejo), patrimônio imaterial, internet e consumo cultural. Repertório: Lei Rouanet (mecenato cultural), IBGE (acesso à cultura), Decreto do Patrimônio Imaterial. Culturas regionais do Tocantins: povos indígenas, ritmos locais (caprichosa, siriri), artesanato. Prática: dissertação sobre a democratização do acesso à cultura.', ['Planeje uma redação sobre a democratização do acesso à cultura no Brasil com dados e proposta específica.', 'Como você incluiria a perspectiva cultural do Tocantins em uma redação sobre cultura brasileira?']),
  createLesson('g1-red-b3-l17', 'L17: Revisão Geral — Preparação para a Prova Final', 'redacao', 'Revisão geral de tudo que foi aprendido no ano de Redação. Checklist completo de competências. Simulado de planejamento: dado o tema, planejar a redação em 10 minutos (sem escrever o texto completo). Revisão dos tipos de argumento. Revisão da proposta de intervenção. Revisão dos conectivos mais importantes. Revisão da estrutura da introdução e conclusão. Confiança: você tem as ferramentas. O que falta é prática constante.', ['Planeje (sem escrever) 3 redações diferentes em 30 minutos (10 min cada).', 'Qual é o seu checklist pessoal de redação? Apresente para a turma.']),
  createLesson('g1-red-b3-l18', 'L18: Revisão do Bimestre 3 e do Semestre', 'redacao', 'Revisão do 3º Bimestre: intensificação do treino, análise de temas reais do ENEM, introdução criativa, conclusão com impacto, coesão avançada, temas (difíceis, contemporâneos, ambientais), checklist pessoal, leitura como suporte, C3 em foco, cultura/arte, preparação para prova. Sexta redação como avaliação final do semestre. Olhar para o ano inteiro: de onde você saiu e onde chegou em termos de redação.', ['Escreva a redação de avaliação do 3º Bimestre (60 minutos).', 'Qual foi o maior aprendizado de Redação neste 3º Bimestre? E no semestre inteiro?']),
];

export const redLessonsB4: Lesson[] = [
  createLesson('g1-red-b4-l1', 'L1: Últimas Práticas do Ano', 'redacao', 'Último bimestre de Redação na 1ª série. Objetivos finais: consolidar as 5 competências, praticar sob pressão de tempo, incorporar o checklist pessoal como rotina. Balanço do ano: evolução de nota por competência, principais aprendizados, lacunas que persistem. Plano de ação para o 4º Bimestre: foco nos pontos mais fracos. Motivação: você está construindo a habilidade que vai valer 1000 pontos no ENEM — e isso demora mais de um ano. O trabalho de agora vale lá na frente.', ['Analise sua trajetória em Redação neste ano: monte um gráfico de evolução.', 'Quais são seus 3 principais objetivos para o 4º Bimestre de Redação?']),
  createLesson('g1-red-b4-l2', 'L2: Redação sobre Temas de Saúde Pública', 'redacao', 'Saúde pública como tema recorrente. Subtemas: acesso ao SUS, saúde mental, vacinação, epidemias, saneamento básico, saúde indígena. Repertório: dados do DATASUS, OMS, IBGE, Lei 8.080/90 (Lei Orgânica da Saúde — SUS), Constituição Federal Art. 196 (saúde como direito). Conceito de determinantes sociais da saúde (moradia, renda, educação afetam a saúde). SUS: conquista histórica e desafios. Prática: dissertação sobre desafios do acesso à saúde nas regiões periféricas do Brasil.', ['Escreva uma redação completa sobre desafios do acesso à saúde pública no Brasil.', 'Como o Cerrado do Tocantins pode ser mencionado em uma redação sobre saúde e meio ambiente?']),
  createLesson('g1-red-b4-l3', 'L3: Redação sobre Temas de Cidadania', 'redacao', 'Cidadania como tema de redação. Subtemas: participação política, voto consciente, analfabetismo político, corrupção, direitos e deveres do cidadão, acesso à justiça. Repertório: Constituição Federal 1988 (Cidadania como fundamento — Art. 1º), dados do TSE sobre participação eleitoral, Transparência Brasil (corrupção). Filosofia política: Aristóteles (o homem é um animal político), Rousseau (contrato social). Prática: redação sobre a importância da educação política para a democracia.', ['Escreva uma redação completa sobre: "Desafios para fortalecer a participação democrática no Brasil".', 'Como você conectaria a filosofia de Rousseau ao tema da cidadania em uma redação?']),
  createLesson('g1-red-b4-l4', 'L4: Prova Bimestral — Redação Completa', 'redacao', 'Avaliação bimestral: redação completa com tema e textos motivadores. 60 minutos. Aplicar todo o aprendizado do ano. Checklist antes de entregar: norma culta, tese, argumentos com evidência, coesão, proposta com 5 elementos. Esta é uma das últimas avaliações formais — demonstrar o crescimento do ano. Feedback completo e detalhado. Análise da turma: média por competência, pontos de força e lacunas coletivas.', ['Escreva a redação da prova bimestral (60 minutos rigorosos).', 'Após a devolutiva: o que você mudaria se pudesse reescrever? Escreva a versão melhorada.']),
  createLesson('g1-red-b4-l5', 'L5: Repertório — Aprofundando para a 2ª Série', 'redacao', 'Construindo repertório para a 2ª série. O repertório precisa crescer continuamente. Categorias para aprofundar: Filosofia (Platão, Aristóteles, Kant, Nietzsche, Hannah Arendt, Foucault, Bourdieu), Sociologia (Durkheim, Weber, Marx, Bauman — "modernidade líquida"), Leis brasileiras (Constituição Federal, ECA, LDB, Lei Maria da Penha, LGPD). Como registrar: caderno de repertório com fichas organizadas por tema. Hábito: a cada notícia relevante, conectar com um conceito do repertório.', ['Construa 10 novas fichas de repertório para o caderno, cobrindo filosofia, sociologia e leis.', 'Para o tema "desigualdade", quais 3 itens do seu repertório são mais pertinentes?']),
  createLesson('g1-red-b4-l6', 'L6: Redação e Interdisciplinaridade', 'redacao', 'A redação do ENEM exige conhecimento de TODAS as áreas. Competência 2: usar conceitos de várias áreas. Como integrar: em um argumento sobre saúde, usar dados de Biologia (impacto de um agente patogênico), contexto histórico (como a doença se difundiu), análise sociológica (quem é mais afetado), economia (custo para o sistema de saúde). A redação perfeita é interdisciplinar. Prática: escrever uma dissertação usando conhecimentos de pelo menos 3 disciplinas diferentes.', ['Escreva uma dissertação sobre: "O impacto do desmatamento do Cerrado na saúde humana" — use Biologia, Geografia e Direito.', 'Como você integrou as disciplinas? Identifique os pontos de conexão.']),
  createLesson('g1-red-b4-l7', 'L7: Encerramento — O Leitor e Escritor que Você Vai Ser', 'redacao', 'Fechamento do ano de Redação. O que você construiu: capacidade de argumentar, organizar ideias, evidenciar posições, propor soluções. Estas habilidades vão muito além do ENEM: você as usará em trabalhos universitários, relatórios profissionais, petições, e-mails formais, apresentações. A escrita argumentativa é a habilidade profissional mais valorizada no Brasil (e no mundo). A Redação do ENEM é um treinamento para a vida adulta. Continue praticando mesmo nas férias.', ['Escreva uma reflexão: o que a Redação te ensinou sobre pensar com clareza?', 'Qual foi a redação que você mais se orgulha de ter escrito este ano? Por quê?']),
  createLesson('g1-red-b4-l8', 'L8: Prática Livre — Escrita Sem Pressão', 'redacao', 'Uma aula de escrita livre: sem tema obrigatório, sem grade de avaliação, sem pressão. Escreva sobre o que você quiser: um texto dissertativo sobre um assunto que te apaixona, uma crônica argumentativa sobre o Tocantins, um artigo de opinião sobre um problema da escola. O objetivo: lembrar que escrever pode ser prazeroso, não apenas obrigatório. A escrita como expressão autêntica. Compartilhar voluntariamente com a turma.', ['Escreva livremente um texto argumentativo sobre algo que te importa profundamente.', 'O que você escreveu hoje que foi diferente das suas redações "normais" do ENEM?']),
  createLesson('g1-red-b4-l9', 'L9: Preparação para a 2ª Série — O que Vem Pela Frente', 'redacao', 'Preview da 2ª série de Redação: aprofundamento das competências, temas mais complexos, maior exigência na argumentação, treino mais intenso. O que você vai precisar: repertório cultural robusto, leitura regular de editoriais e notícias, prática semanal de redação (mesmo fora das aulas). Metas para as férias: ler 1 editorial por semana, escrever 1 parágrafo argumentativo por semana, montar 5 novas fichas de repertório por mês. A 2ª série começa agora.', ['Escreva suas metas de Redação para as férias e para a 2ª série.', 'O que você vai ler nas férias que vai enriquecer seu repertório para a redação?']),
  createLesson('g1-red-b4-l10', 'L10: Revisão Final e Celebração', 'redacao', 'Última aula de Redação da 1ª série. Revisão rápida: as 5 competências, a estrutura da dissertação, os tipos de argumento, a proposta de intervenção. Celebração: compartilhar a melhor redação do ano — cada aluno lê um parágrafo do seu texto favorito. Portfólio final: colecionar todas as redações do ano e ver a evolução. Mensagem: você passou de alguém que talvez soubesse o que é "dissertação argumentativa" para alguém que sabe FAZÊ-LA. Isso tem valor real. Parabéns!', ['Leia em voz alta o parágrafo de que você mais se orgulha em todo o ano de Redação.', 'Escreva uma mensagem para o seu eu da 2ª série: conselhos sobre Redação.']),
  createLesson('g1-red-b4-l11', 'L11: Prática de Planejamento Intensivo', 'redacao', 'Aula dedicada ao planejamento de redações — sem escrever os textos completos. Dado um tema, planejar em 10 minutos: tese, 2 argumentos, evidências para cada, proposta com 5 elementos. Praticar 4 planejamentos em 40 minutos (10 min cada). O planejamento é a parte mais importante — uma redação bem planejada é difícil de travar no meio. Comparar os planejamentos em grupo: qual tese é mais forte? Qual proposta é mais específica?', ['Realize 4 planejamentos de redação (10 minutos cada) para 4 temas diferentes.', 'Compare seus planejamentos com os de um colega: qual proposta de intervenção é mais específica?']),
  createLesson('g1-red-b4-l12', 'L12: Temas de Atualidade — 2024/2025', 'redacao', 'Temas de atualidade que podem aparecer no ENEM dos próximos anos. Análise de eventos recentes: o que está acontecendo no Brasil e no mundo que pode se tornar tema de redação? Inteligência artificial e regulação, desafios climáticos pós-COP, questões indígenas (Demarcação de Terras), saúde mental pós-pandemia, fake news e democracia, direitos digitais. Para cada tema: problema social, dois lados, proposta possível. Construindo flexibilidade temática.', ['Para 3 temas de atualidade, escreva: o problema social central, dois pontos de vista e uma proposta.', 'Qual tema de atualidade você acha mais provável no ENEM? Justifique com base nos padrões históricos.']),
  createLesson('g1-red-b4-l13', 'L13: Leitura de Editoriais como Treino', 'redacao', 'Estratégia de treino passivo: ler editoriais de jornais regularmente melhora a escrita argumentativa sem exigir escrever. Como ler ativamente um editorial: identificar tese, argumentos, conectivos, proposta. Imitar estrutura: escrever um parágrafo no estilo do editorial. Editoriais recomendados: Folha de S.Paulo (opinião), O Globo (editorial), Nexo Jornal (análise), Agência Pública (jornalismo investigativo). Ler e anotar: o que posso usar na redação? Qual argumento deste editorial eu poderia usar?', ['Leia um editorial de jornal e faça um mapa da estrutura argumentativa: tese, argumentos, evidências, conclusão.', 'Imite o estilo do editorial: reescreva um parágrafo sobre outro tema usando a mesma estrutura.']),
  createLesson('g1-red-b4-l14', 'L14: Revisão Final — O Ano em Perspectiva', 'redacao', 'Revisão final de todo o ano de Redação. Em janeiro, o que você sabia? Agora, o que sabe? Em janeiro, o que você podia escrever? Agora, o que pode? A diferença é o crescimento. Revisão das 5 competências. Revisão da estrutura. Revisão dos tipos de argumento. Revisão da proposta de intervenção. Revisão dos conectivos. Teste rápido: perguntas sobre cada ponto — que porcentagem você acerta? Objetivo: sair da 1ª série sabendo claramente o que é e como fazer uma dissertação argumentativa.', ['Faça o teste rápido de revisão: 20 perguntas sobre os conteúdos de Redação do ano.', 'Qual foi a maior transformação na sua escrita neste ano?']),
  createLesson('g1-red-b4-l15', 'L15: Escrita Colaborativa', 'redacao', 'Redação em grupo: cada grupo recebe um tema e divide a redação (cada aluno escreve um parágrafo). Depois: juntar, revisar, garantir coesão entre os parágrafos. Aprendizado: ver como outros abordam o mesmo tema, negociar a tese em grupo, garantir coesão entre parágrafos escritos por pessoas diferentes. A experiência de escrever colaborativamente desenvolve consciência sobre o texto como todo. Apresentação das redações coletivas para a turma.', ['Participe da escrita colaborativa: escreva seu parágrafo e depois ajude a revisar a redação completa.', 'O que foi mais difícil na escrita colaborativa: a tese, o argumento ou a coesão? Por quê?']),
  createLesson('g1-red-b4-l16', 'L16: Portfólio e Avaliação Final', 'redacao', 'Organização do portfólio de redações do ano. Selecionar: a primeira redação, a melhor redação, a que mais evoluiu da versão inicial. Comparar as 3: ver o crescimento concreto. Autoavaliação final: nota que você se daria em cada competência com base em todo o ano. Avaliação do professor: feedback final holístico. Próximos passos: o que trabalhar na 2ª série para garantir uma nota excelente no ENEM.', ['Monte seu portfólio de Redação com as 3 redações selecionadas e uma autoavaliação de cada.', 'O que você vai fazer diferente na 2ª série para elevar sua nota de Redação?']),
  createLesson('g1-red-b4-l17', 'L17: Motivação e Encerramento', 'redacao', 'Aula final de motivação. A redação do ENEM é uma oportunidade — não uma ameaça. Com preparação consistente, qualquer pessoa pode atingir 700+ de nota. Não é sobre talento — é sobre prática. Cada redação que você escreve melhora a próxima. O hábito de escrever desenvolvido neste ano vai durar a vida inteira. Lembrar: você aprendeu a organizar o pensamento, a argumentar com evidências, a propor soluções. Estas são habilidades que o mercado, a universidade e a vida exigem.', ['Escreva uma mensagem motivacional para um colega que está com medo da Redação do ENEM.', 'O que você diria para um estudante de 1ª série que está começando esta jornada?']),
  createLesson('g1-red-b4-l18', 'L18: Encerramento do Ano — Celebração Final', 'redacao', 'A última aula de Redação da 1ª série. Celebração: cada aluno lê a abertura de sua melhor redação do ano. O professor compartilha a evolução da turma (gráfico de notas médias ao longo do ano — anonimizado). Agradecimento mútuo: professor e alunos. Mensagem final: você está mais preparado do que pensa. Continue praticando. A redação de 1000 pontos está ao seu alcance — mas ela se constrói ao longo de 3 anos, não em uma semana antes do ENEM.', ['Leia a abertura da sua melhor redação do ano para a turma.', 'Escreva uma promessa de Redação para o seu futuro eu na 2ª série.']),
];
